module top_module(
    in_1, 
    in_2, 
    out, 
    obf_CTRL
    );parameter BITWIDTH = 32;

    input [BITWIDTH-1 : 0]  in_1;
    input [BITWIDTH-1 : 0]  in_2;
    input                   obf_CTRL;

    output [BITWIDTH-1 : 0] out;

    assign out = (obf_CTRL == 1'b0) ? in_1 : in_2;

endmodule
